            method: 'GET',
            redirect: 'follow',
            signal: controller.signal,
            headers: {
                Accept: 'image/*,*/*;q=0.8',
                'Accept-Encoding': 'identity',
                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
