        throw {status: 500, error: 'failed to fetch journal'};
    }

    if(!journal){
        throw {status: 404, error: 'journal not found'};
    }

    if(!journal.is_repost){
        throw {status: 400, error: 'journal is not a repost'};
    }

    const {error: updateError} = await supabase
