    if (!story) return story;
    const { embedding, ...rest } = story;
    return rest;
};

const STORY_SELECT_COLUMNS = `
    id,
    author_id,
    title,
    description,
    cover_url,
    status,
    tags,
    privacy,
    read_count,
    vote_count,
