const parseLimitWithinRange = (value, min, max, fallback = null) => {
    const parsed = Number.parseInt(value, 10);
    if (Number.isNaN(parsed)) {
        return fallback;
    }
    if (parsed < min || parsed > max) {
        return null;
    }
    return parsed;
};

